            <p style="margin-bottom: 20px;">&copy; 2024 Cyclopath. All Rights Reserved.</p>
            <div class="footer-links">
                <a href="#">로그인</a>
                <a href="#">회사소개</a>
                <a href="#">채용정보</a>
            </div>
        </div>
    </footer>

    <script>
        document.addEventListener('DOMContentLoaded', function() {
            // Intersection Observer for Fade-In Animation
            const faders = document.querySelectorAll('.fade-in-element');

            const observerOptions = {
                root: null,
                rootMargin: '0px',
                threshold: 0.1 
            };

            const observer = new IntersectionObserver((entries, observer) => {
                entries.forEach(entry => {
                    if (entry.isIntersecting) {
                        const element = entry.target;
                        const delay = parseFloat(element.dataset.delay) || 0;

                        // Apply a timeout based on data-delay for staggered effect
                        setTimeout(() => {
                            element.classList.add('visible');
                        }, delay * 1000); 

                        observer.unobserve(element); // Stop observing once visible
                    }
                });
            }, observerOptions);

            faders.forEach(el => {
                observer.observe(el);
            });
        });
    </script>
</body>
